import{c as t,S as h,j as i,m as a}from"./chunks/framework.8aa1YH_s.js";const l=JSON.parse('{"title":"Hướng dẫn cho Quản trị viên","description":"","frontmatter":{},"headers":[],"relativePath":"admin/index.md","filePath":"admin/index.md","lastUpdated":0}'),e={name:"admin/index.md"};function o(d,n,r,c,u,g){return h(),i("div",null,[...n[0]||(n[0]=[a('<h1 id="huong-dan-cho-quan-tri-vien" tabindex="-1">Hướng dẫn cho Quản trị viên <a class="header-anchor" href="#huong-dan-cho-quan-tri-vien" aria-label="Permalink to “Hướng dẫn cho Quản trị viên”">​</a></h1><p>Khu vực Admin (<code>https://lamsonedutech.vn/admin/...</code>) là trung tâm điều hành toàn bộ hệ thống LamSơn Edutech. Trang này tóm tắt <strong>những việc một quản trị viên cần làm</strong> và link tới hướng dẫn chi tiết.</p><h2 id="so-đo-menu-admin" tabindex="-1">Sơ đồ menu Admin <a class="header-anchor" href="#so-đo-menu-admin" aria-label="Permalink to “Sơ đồ menu Admin”">​</a></h2><p>Sau khi đăng nhập tại <code>https://lamsonedutech.vn/auth/admin</code>, bạn sẽ thấy menu bên trái với các nhóm chức năng:</p><table tabindex="0"><thead><tr><th>Nhóm</th><th>Mục con</th><th>Đường dẫn</th></tr></thead><tbody><tr><td><strong>Dashboard</strong></td><td>Trang tổng quan</td><td><code>https://lamsonedutech.vn/admin/dashboard</code></td></tr><tr><td><strong>Thống kê</strong></td><td>Khóa học, Giáo viên, Học viên, Kết quả thi</td><td><code>https://lamsonedutech.vn/admin/statistic/...</code></td></tr><tr><td><strong>Thành viên</strong></td><td>Học viên, Giáo viên, Nhân viên, Quản lý quyền</td><td><code>https://lamsonedutech.vn/admin/account/...</code></td></tr><tr><td><strong>Đào tạo</strong></td><td>Khung chương trình, Khóa học, Chương, Chuyên đề, Bài giảng, Thông tin khóa học</td><td><code>https://lamsonedutech.vn/admin/thematic/...</code>, <code>https://lamsonedutech.vn/admin/lesson/...</code>, <code>https://lamsonedutech.vn/admin/educate/...</code></td></tr><tr><td><strong>Danh mục đề thi</strong></td><td>Tiêu chí, Trích đoạn, Đề ôn, Đề mẫu luyện thi, Đánh giá, Câu hỏi, Bộ đề thi</td><td><code>https://lamsonedutech.vn/admin/question/...</code></td></tr><tr><td><strong>Kinh doanh</strong></td><td>Học viên - Khóa học, Khuyến mãi, Chiết khấu, Hóa đơn, Đại lý</td><td><code>https://lamsonedutech.vn/admin/business/...</code></td></tr><tr><td><strong>Hỏi đáp</strong></td><td>Quản lý câu hỏi của học viên</td><td><code>https://lamsonedutech.vn/admin/reply</code></td></tr><tr><td><strong>Banner</strong></td><td>Quảng cáo, Menu</td><td><code>https://lamsonedutech.vn/admin/banner/...</code></td></tr><tr><td><strong>Hệ thống</strong></td><td>Ngân hàng, Footer, Liên hệ</td><td><code>https://lamsonedutech.vn/admin/system/...</code></td></tr></tbody></table><h2 id="quy-trinh-thiet-lap-he-thong-lan-đau" tabindex="-1">Quy trình thiết lập hệ thống lần đầu <a class="header-anchor" href="#quy-trinh-thiet-lap-he-thong-lan-đau" aria-label="Permalink to “Quy trình thiết lập hệ thống lần đầu”">​</a></h2><p>Nếu bạn vừa được giao một hệ thống trống, hãy thực hiện theo thứ tự sau để tránh thiếu dữ liệu phụ thuộc:</p><ol><li><p><strong>Cấu hình hệ thống</strong> (Hệ thống → Ngân hàng / Footer / Liên hệ). → Xem <a href="./he-thong">Hệ thống</a>.</p></li><li><p><strong>Tạo phân quyền &amp; nhân viên nội bộ</strong> (Thành viên → Quản lý quyền, sau đó Thành viên → Nhân viên). → Xem <a href="./phan-quyen">Phân quyền</a>, <a href="./quan-ly-nhan-vien">Quản lý nhân viên</a>.</p></li><li><p><strong>Tạo tài khoản giáo viên</strong> (Thành viên → Giáo viên). → Xem <a href="./quan-ly-giao-vien">Quản lý giáo viên</a>.</p></li><li><p><strong>Tạo khung chương trình &amp; danh mục đào tạo</strong> (Đào tạo → Khung chương trình → Khóa học → Chương → Chuyên đề → Bài giảng). → Xem <a href="./khung-chuong-trinh">Khung chương trình</a>, <a href="./khoa-hoc">Khóa học</a>, <a href="./chuong-chuyen-de">Chương / Chuyên đề</a>, <a href="./bai-giang">Bài giảng</a>.</p></li><li><p><strong>Tạo ngân hàng câu hỏi &amp; đề thi</strong> (Danh mục đề thi → Câu hỏi → Tiêu chí → Đề ôn / Đề mẫu / Bộ đề). → Xem <a href="./danh-muc-cau-hoi">Danh mục câu hỏi</a>, <a href="./tieu-chi-de-thi">Tiêu chí đề thi</a>, <a href="./de-mau-luyen-thi">Đề mẫu luyện thi</a>.</p></li><li><p><strong>Cấu hình kinh doanh</strong> (Kinh doanh → Khuyến mãi, Chiết khấu, Đại lý). → Xem <a href="./khuyen-mai">Khuyến mãi</a>, <a href="./chiet-khau">Chiết khấu</a>.</p></li><li><p><strong>Trang chủ &amp; truyền thông</strong> (Banner → Quảng cáo, Menu). → Xem <a href="./banner-menu">Banner &amp; Menu</a>.</p></li></ol><h2 id="viec-thuong-ngay-cua-admin" tabindex="-1">Việc thường ngày của Admin <a class="header-anchor" href="#viec-thuong-ngay-cua-admin" aria-label="Permalink to “Việc thường ngày của Admin”">​</a></h2><ul><li><strong>Sáng:</strong> kiểm tra Dashboard, xem hóa đơn mới, học viên mới đăng ký.</li><li><strong>Theo dõi tuần/tháng:</strong> vào Thống kê để xem doanh thu, số học viên hoạt động, kết quả thi.</li><li><strong>Hỗ trợ:</strong> trả lời / chuyển tiếp Hỏi đáp; tra cứu hóa đơn khi học viên khiếu nại.</li><li><strong>Định kỳ:</strong> mở bộ đề thi mới, tạo mã khuyến mãi, cập nhật banner.</li></ul><h2 id="luu-y-quan-trong" tabindex="-1">Lưu ý quan trọng <a class="header-anchor" href="#luu-y-quan-trong" aria-label="Permalink to “Lưu ý quan trọng”">​</a></h2><div class="warning custom-block"><p class="custom-block-title">Bảo mật</p><ul><li>Không chia sẻ tài khoản admin. Tạo riêng tài khoản nhân viên với quyền vừa đủ.</li><li>Đăng xuất khi rời máy.</li><li>Đổi mật khẩu định kỳ.</li></ul></div><div class="tip custom-block"><p class="custom-block-title">Sao lưu dữ liệu</p><ul><li>Trước khi xóa hàng loạt (học viên, khóa học, đề thi), hãy yêu cầu IT <strong>backup dữ liệu</strong>.</li><li>Việc xóa nội dung đã có học viên đang học có thể làm hỏng tiến độ học của họ.</li></ul></div><h2 id="tiep-theo" tabindex="-1">Tiếp theo <a class="header-anchor" href="#tiep-theo" aria-label="Permalink to “Tiếp theo”">​</a></h2><p>→ Bắt đầu với <a href="./dashboard">Dashboard</a> hoặc đi thẳng đến nhóm chức năng bạn cần ở menu bên trái.</p>',15)])])}const m=t(e,[["render",o]]);export{l as __pageData,m as default};
